const https = require('https');
const http = require('http');
const cfg = $('配置参数').first().json;
const baseUrl = (cfg.scraperApiUrl || 'http://127.0.0.1:3001').replace('localhost', '127.0.0.1');
const platforms = ['boss'];
const scraperConfig = { keywords: cfg.keywords, cityCode: cfg.cityCode, maxJobs: cfg.maxJobsPerPlatform || 25, headless: true };

function httpPost(urlStr, body) {
  return new Promise((resolve, reject) => {
    const noProto = urlStr.replace('https://', '').replace('http://', '');
    const proto = urlStr.startsWith('https') ? 'https' : 'http';
    const slashIdx = noProto.indexOf('/');
    const hostPort = slashIdx === -1 ? noProto : noProto.slice(0, slashIdx);
    const pathname = slashIdx === -1 ? '/' : noProto.slice(slashIdx);
    const colonIdx = hostPort.indexOf(':');
    const host = colonIdx === -1 ? hostPort : hostPort.slice(0, colonIdx);
    const port = colonIdx === -1 ? (proto === 'https' ? 443 : 80) : parseInt(hostPort.slice(colonIdx + 1));
    const lib = proto === 'https' ? https : http;
    const options = { hostname: host, port, path: pathname, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) } };
    const req = lib.request(options, res => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve([]); } });
    });
    req.on('error', reject);
    req.setTimeout(900000, () => { req.destroy(new Error('timeout')); });
    req.write(body);
    req.end();
  });
}

const allJobs = [];
const errors = [];

for (const platform of platforms) {
  try {
    const jobs = await httpPost(baseUrl + '/scrape/' + platform, JSON.stringify(scraperConfig));
    const jobList = Array.isArray(jobs) ? jobs : [];
    for (const job of jobList) allJobs.push({ ...job, source_platform: job.source || platform });
    console.log(platform + ' 爬取完成，获取 ' + jobList.length + ' 个职位');
  } catch (e) {
    console.log(platform + ' 爬取失败: ' + e.message);
    errors.push(platform + ': ' + e.message);
  }
}

console.log('所有平台合计: ' + allJobs.length + ' 个职位');
if (allJobs.length === 0) return [{ json: { _placeholder: true, message: '所有平台爬取结果为空', errors } }];
return allJobs.map(job => ({ json: job }));

// 关键词过滤 + 去重 + 工作经验筛选（应届/1-3年）
const allJobs = $input.all().map(i => i.json);
const cfg = $('配置参数').first().json;
const keywords = cfg.keywords || [];

const realJobs = allJobs.filter(j => !j._placeholder);
if (realJobs.length === 0) {
  console.log('无真实职位数据，跳过过滤');
  return [{ json: { _placeholder: true, message: '无职位数据' } }];
}

// 去重
const seen = new Set();
const unique = realJobs.filter(job => {
  const key = (job.job_title || '').trim() + '|' + (job.company_name || '').trim();
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// 工作经验筛选：保留应届/1-3年，排除明确5年以上
const KEEP_EXP = [/应届/, /不限/, /1[-~至到]3年?/, /[123]年/, /1-3/, /2-3/, /校招/, /实习/, /junior/i, /graduate/i];
const EXCLUDE_EXP = [/[5-9]年以上/, /10年/, /八年/, /七年/, /六年/, /五年以上/];
const expFiltered = unique.filter(job => {
  const expText = [job._job_experience || '', job.description || '', job.job_title || ''].join(' ');
  if (EXCLUDE_EXP.some(r => r.test(expText))) return false;
  const expTag = (job._job_experience || '').trim();
  if (expTag) return KEEP_EXP.some(r => r.test(expTag));
  return true;
});

// 关键词过滤
const filtered = keywords.length === 0 ? expFiltered : expFiltered.filter(job => {
  const text = [job.job_title || '', job.description || '', job.requirements || '', (job._skills || []).join(' ')].join(' ').toLowerCase();
  return keywords.some(kw => text.includes(kw.toLowerCase()));
});

console.log('去重前: ' + realJobs.length + ' | 去重后: ' + unique.length + ' | 经验筛选后: ' + expFiltered.length + ' | 关键词过滤后: ' + filtered.length);
if (filtered.length === 0) return [{ json: { _placeholder: true, message: '过滤后无匹配职位' } }];
return filtered.map(job => ({ json: job }));

const https = require('https');
const http = require('http');
const jobs = $input.all().map(i => i.json);
const cfg = $('配置参数').first().json;
const llmUrl = cfg.llmBaseUrl || 'https://api.anthropic.com';
const llmToken = cfg.llmToken;
const llmModel = cfg.llmModel || 'claude-sonnet-4-6';
const userResume = cfg.userResume || '求职者简历信息未填写';
const preferences = cfg.preferences || '';

const realJobs = jobs.filter(j => !j._placeholder);
if (realJobs.length === 0) return [{ json: { message: '没有职位需要评分' } }];

function httpsPost(urlStr, headers, body) {
  return new Promise((resolve, reject) => {
    const noProto = urlStr.replace('https://', '').replace('http://', '');
    const proto = urlStr.startsWith('https') ? 'https' : 'http';
    const slashIdx = noProto.indexOf('/');
    const hostPort = slashIdx === -1 ? noProto : noProto.slice(0, slashIdx);
    const pathname = slashIdx === -1 ? '/' : noProto.slice(slashIdx);
    const colonIdx = hostPort.indexOf(':');
    const host = colonIdx === -1 ? hostPort : hostPort.slice(0, colonIdx);
    const port = colonIdx === -1 ? (proto === 'https' ? 443 : 80) : parseInt(hostPort.slice(colonIdx + 1));
    const lib = proto === 'https' ? https : http;
    const options = { hostname: host, port, path: pathname, method: 'POST', headers: { ...headers, 'Content-Length': Buffer.byteLength(body) } };
    const req = lib.request(options, res => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    req.setTimeout(180000, () => { req.destroy(new Error('LLM timeout')); });
    req.write(body);
    req.end();
  });
}

function callLLM(prompt, maxTokens) {
  const body = JSON.stringify({ model: llmModel, max_tokens: maxTokens, messages: [{ role: 'user', content: prompt }] });
  return httpsPost(llmUrl + '/chat/completions', { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + llmToken }, body);
}

const MAX_JOBS = Math.min(realJobs.length, 80);
const jobsSummary = realJobs.slice(0, MAX_JOBS).map((job, i) => {
  const desc = (job.description || job.requirements || '').slice(0, 400);
  return '[' + (i+1) + '] 职位: ' + (job.job_title||'未知') + ' | 公司: ' + (job.company_name||'未知') + ' | 薪资: ' + (job.salary_range||'面议') + ' | 地点: ' + (job.location||'未知') + '\n描述: ' + (desc||'暂无描述');
}).join('\n\n');

const scoringPrompt = '你是一位专业的求职顾问和简历优化专家。\n\n求职者简历：\n' + userResume + '\n\n求职偏好：\n' + preferences + '\n\n以下是招聘平台职位（共' + MAX_JOBS + '个）：\n' + jobsSummary + '\n\n任务：\n1. 评估每个职位与求职者的匹配度（0-100分）\n2. 选出最高的20个职位\n3. 对每个入选职位提供：\n   - jd_summary: 该公司最看重的3-5个核心能力/特质（根据JD提炼，50字以内）\n   - resume_suggestions: 针对求职者当前简历的具体修改建议，必须指出「在简历哪个部分（如：面壁智能实习经历/项目经历/自我评价）增加/修改/突出什么内容」，100-150字，不得泛泛而谈\n\n严格按JSON返回（只返回JSON）：\n{\n  \"top_jobs\": [\n    {\n      \"original_index\": 1,\n      \"match_score\": 92,\n      \"match_reason\": \"匹配理由，50字以内\",\n      \"jd_summary\": \"公司最看重的核心能力/特质\",\n      \"resume_suggestions\": \"具体指出在简历哪部分做什么修改\"\n    }\n  ]\n}';

let llmResult = { top_jobs: [] };
try {
  const data = await callLLM(scoringPrompt, 6000);
  const content = data?.choices?.[0]?.message?.content || '{}';
  const jsonMatch = content.match(/{[sS]*}/);
  if (jsonMatch) llmResult = JSON.parse(jsonMatch[0]);
} catch (e) {
  console.error('LLM评分调用失败:', e.message);
  llmResult = { top_jobs: realJobs.slice(0, 20).map((_, i) => ({ original_index: i+1, match_score: 0, match_reason: 'LLM暂不可用', jd_summary: '', resume_suggestions: '请手动查看' })) };
}

const enrichedJobs = (llmResult.top_jobs || []).map(t => {
  const orig = realJobs[(t.original_index||1)-1] || {};
  return { ...orig, match_score: t.match_score||0, match_reason: t.match_reason||'', jd_summary: t.jd_summary||'', resume_suggestions: t.resume_suggestions||'' };
}).sort((a, b) => b.match_score - a.match_score);

console.log('LLM评分完成，入选: ' + enrichedJobs.length + '个');

let summaryRecord = null;
if (realJobs.length >= 100) {
  console.log('达到100条，触发全局总结...');
  const allJdTexts = realJobs.slice(0, 100).map((job, i) => '[' + (i+1) + '] ' + (job.job_title||'') + ': ' + (job.description||'').slice(0, 200)).join('\n');
  const summaryPrompt = '以下是100条招聘岗位的JD摘要：\n' + allJdTexts + '\n\n求职者简历：\n' + userResume + '\n\n请完成两个任务：\n1. 总结这批岗位普遍最看重的5-8个核心特质/能力（按频次排序，每条20字以内）\n2. 根据这些高频需求，推荐3-5个适合求职者现在学习/实践的具体项目方向（说明项目名称、学习平台/资源、与岗位需求的关联）\n\n按JSON返回：\n{\n  \"market_insights\": [\"特质1\", \"特质2\"],\n  \"recommended_projects\": [\n    { \"name\": \"项目名称\", \"platform\": \"学习平台/资源\", \"relevance\": \"与岗位需求的关联\" }\n  ]\n}';
  try {
    const sumData = await callLLM(summaryPrompt, 3000);
    const sumContent = sumData?.choices?.[0]?.message?.content || '{}';
    const sumMatch = sumContent.match(/{[sS]*}/);
    if (sumMatch) {
      const sumResult = JSON.parse(sumMatch[0]);
      summaryRecord = {
        _is_summary: true,
        job_title: '【市场洞察总结】',
        company_name: '系统生成',
        match_score: 0,
        match_reason: '',
        jd_summary: '市场高频需求: ' + (sumResult.market_insights || []).join('、'),
        resume_suggestions: '推荐学习项目:\n' + (sumResult.recommended_projects || []).map(p => '・' + p.name + '（' + p.platform + '）- ' + p.relevance).join('\n'),
        salary_range: '', location: '', application_url: '', source: 'system',
      };
      console.log('全局总结生成成功');
    }
  } catch (e) { console.error('全局总结调用失败:', e.message); }
}

const output = enrichedJobs.map(job => ({ json: job }));
if (summaryRecord) output.push({ json: summaryRecord });
return output;

const https = require('https');
const jobs = $input.all().map(i => i.json).filter(j => !j._placeholder && j.job_title);
const cfg = $('配置参数').first().json;
const { feishuAppId, feishuAppSecret, feishuAppToken, feishuTableId } = cfg;

if (jobs.length === 0) return [{ json: { success: false, message: '无有效职位数据' } }];

function httpsPost(urlStr, token, body) {
  return new Promise((resolve, reject) => {
    const noProto = urlStr.replace('https://', '').replace('http://', '');
    const slashIdx = noProto.indexOf('/');
    const hostPort = slashIdx === -1 ? noProto : noProto.slice(0, slashIdx);
    const pathname = slashIdx === -1 ? '/' : noProto.slice(slashIdx);
    const colonIdx = hostPort.indexOf(':');
    const host = colonIdx === -1 ? hostPort : hostPort.slice(0, colonIdx);
    const port = colonIdx === -1 ? 443 : parseInt(hostPort.slice(colonIdx + 1));
    const headers = { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(body) };
    if (token) headers['Authorization'] = 'Bearer ' + token;
    const options = { hostname: host, port, path: pathname, method: 'POST', headers };
    const req = https.request(options, res => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({}); } });
    });
    req.on('error', reject);
    req.write(body);
    req.end();
  });
}

let accessToken;
try {
  const tokenData = await httpsPost('https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal', null, JSON.stringify({ app_id: feishuAppId, app_secret: feishuAppSecret }));
  accessToken = tokenData.tenant_access_token;
  if (!accessToken) throw new Error('获取Token失败: ' + JSON.stringify(tokenData));
  console.log('飞书Token获取成功');
} catch (e) {
  console.error('飞书授权失败:', e.message);
  return [{ json: { success: false, error: e.message } }];
}

const todayTs = Date.now();
const records = jobs.map(job => ({
  fields: {
    '职位名称': job.job_title || '未知',
    '公司名称': job.company_name || '未知',
    '招聘平台': job.source_platform || job.source || '未知',
    '薪资范围': job.salary_range || '面议',
    '匹配度评分': String(job.match_score || 0),
    '匹配理由': job.match_reason || '',
    '岗位核心要求': job.jd_summary || '',
    '简历修改建议': job.resume_suggestions || '',
    '职位链接': job.application_url ? { link: job.application_url, text: job.job_title || '' } : { link: '', text: '' },
    '采集日期': todayTs,
  }
}));

const results = [];
for (let i = 0; i < records.length; i += 100) {
  const batch = records.slice(i, i + 100);
  try {
    const r = await httpsPost('https://open.feishu.cn/open-apis/bitable/v1/apps/' + feishuAppToken + '/tables/' + feishuTableId + '/records/batch_create', accessToken, JSON.stringify({ records: batch }));
    results.push(r);
    console.log('批次写入 ' + batch.length + ' 条，code: ' + r.code);
  } catch (e) { console.error('批次写入失败:', e.message); }
}

return [{ json: { success: true, synced_count: jobs.length, feishu_results: results } }];
